def cleanup():
    """Stops the server and removes generated files."""
    print("\n[Cleanup] Stopping server...")
    if global_server_instance:
        # Graceful shutdown (0 seconds grace)
        global_server_instance.stop(grace=0)
    print("[Cleanup] Removing generated files...")
    for f in [PROTO_FILE, PB2_FILE, PB2_GRPC_FILE]:
        if os.path.exists(f):
            os.remove(f)
    # Remove __pycache__ directory if it exists
    if os.path.exists("__pycache__"):
        shutil.rmtree("__pycache__")
    print("[Cleanup] Cleanup complete.")

